mapper.update:
UPDATE student_profile_guided_sessions
SET current_stage = #{currentStage},
    last_generated_version_no = #{lastGeneratedVersionNo}
WHERE session_id = #{sessionId}

mapper.select:
SELECT *
FROM student_profile_guided_sessions
WHERE session_id = #{sessionId}
  AND student_id = #{studentId}
  AND delete_flag = '1'
LIMIT 1

SELECT COALESCE(MAX(sequence_no), 0) + 1
FROM student_profile_guided_messages
WHERE session_id = #{sessionId}

SELECT id
FROM student_profile_guided_messages
WHERE session_id = #{sessionId}
  AND message_role = #{role}
  AND message_kind = #{kind}
  AND question_code = #{questionCode}
  AND delete_flag = '1'
ORDER BY sequence_no DESC, id DESC
LIMIT 1
